21	// US-052 — Create-campaign wizard step 4 (sample videos + max submissions).
22	// Per-row URL validation reuses `classifyVideoUrl` from `src/lib/oembed.ts`
23	// so the wizard preview and the server-side submit path (US-046 / the
24	// submit-video edge function) agree on what counts as a TikTok or Instagram
25	// URL. Empty rows are allowed and will be filtered at publish (step-5) —
26	// Next stays enabled so users can still navigate while drafting, and step-5
27	// is the final gate before the listing is created.
28	//
29	// max_submissions maps 1:1 onto `listings.max_submissions` (integer nullable,
30	// docs/tech-architecture.md §4.7). Empty input = null = "no cap".
31	
32	// Digits-only filter for the max-submissions field. 5-digit cap keeps real
33	// inputs well under int32 without needing an explicit range check.
34	const MAX_SUBMISSIONS_RE = /^\d*$/;
35	const MAX_SUBMISSIONS_DIGITS = 5;
