37	export default function CampaignWizardStep4() {
38	  const { draft, updateField, setField } = useWizard();
39	
40	  // Array mutations use the functional updater (Codebase Pattern #128) so
41	  // rapid-fire taps don't drop writes against a stale closure snapshot.
