1	import AsyncStorage from '@react-native-async-storage/async-storage';
2	import {
3	  createContext,
4	  useCallback,
5	  useContext,
6	  useEffect,
7	  useMemo,
8	  useRef,
9	  useState,
10	  type ReactNode,
11	} from 'react';
12	
13	// Campaign-creation wizard state (US-049 through US-053). React-context + AsyncStorage
14	// persistence — not MMKV, because `react-native-mmkv` v4 is a Nitro module that
15	// cannot load in Expo Go (see Codebase Pattern #105, progress.txt). AsyncStorage
16	// satisfies the AC's "wizard store + MMKV" intent with a transport that actually
17	// boots in Expo Go. The wizard draft is not secret material, so AsyncStorage (vs
18	// expo-secure-store) is the correct fit.
19	//
20	// Shape covers all five steps up front so later stories (US-050 pre-conditions,
21	// US-051 post-conditions, US-052 samples + max, US-053 publish) can read and
22	// write their slices without a store rewrite. Step 1 (this story) only wires the
23	// first four fields; the rest are kept with empty-array / null defaults.
24	
25	export type WizardCurrency = 'USD' | 'EUR' | 'GBP';
26	
27	export type WizardPreConditionPlatform = 'tiktok' | 'instagram';
28	export type WizardPreConditionMetric = 'followers' | 'avg_views';
29	
30	export type WizardPreCondition = {
31	  id: string;
32	  platform: WizardPreConditionPlatform;
33	  metric: WizardPreConditionMetric;
34	  threshold: number;
35	};
36	
37	export type WizardPostCondition = {
38	  id: string;
39	  text: string;
40	};
41	
42	export type WizardDraft = {
43	  title: string;
44	  description: string;
45	  priceCents: number | null;
46	  currency: WizardCurrency;
47	  preConditions: WizardPreCondition[];
48	  postConditions: WizardPostCondition[];
49	  sampleUrls: string[];
50	  maxSubmissions: number | null;
51	};
52	
53	const EMPTY_DRAFT: WizardDraft = {
54	  title: '',
55	  description: '',
56	  priceCents: null,
57	  currency: 'USD',
58	  preConditions: [],
59	  postConditions: [],
60	  sampleUrls: [],
61	  maxSubmissions: null,
62	};
63	
64	const STORAGE_KEY = '@marketify/campaign-wizard-draft/v1';
65	const PERSIST_DEBOUNCE_MS = 250;
66	
67	type WizardContextValue = {
68	  draft: WizardDraft;
69	  hydrated: boolean;
70	  setField: <K extends keyof WizardDraft>(key: K, value: WizardDraft[K]) => void;
71	  // Functional updater for fields whose next value depends on the previous —
72	  // callers that close over `draft.<key>` in rapid-fire handlers (e.g. "add row
73	  // to preConditions" pressed twice before a re-render) would otherwise drop
74	  // writes because the captured snapshot is stale.
75	  updateField: <K extends keyof WizardDraft>(
76	    key: K,
77	    updater: (prev: WizardDraft[K]) => WizardDraft[K],
78	  ) => void;
79	  setPartial: (patch: Partial<WizardDraft>) => void;
80	  resetDraft: () => Promise<void>;
81	};
82	
83	const WizardContext = createContext<WizardContextValue | null>(null);
84	
85	function isWizardDraftShape(value: unknown): value is WizardDraft {
86	  if (!value || typeof value !== 'object') return false;
87	  const v = value as Record<string, unknown>;
88	  return (
89	    typeof v.title === 'string' &&
90	    typeof v.description === 'string' &&
91	    (v.priceCents === null || typeof v.priceCents === 'number') &&
92	    (v.currency === 'USD' || v.currency === 'EUR' || v.currency === 'GBP') &&
93	    Array.isArray(v.preConditions) &&
94	    Array.isArray(v.postConditions) &&
95	    Array.isArray(v.sampleUrls) &&
96	    (v.maxSubmissions === null || typeof v.maxSubmissions === 'number')
97	  );
98	}
99	
100	export function WizardProvider({ children }: { children: ReactNode }) {
101	  const [draft, setDraft] = useState<WizardDraft>(EMPTY_DRAFT);
102	  const [hydrated, setHydrated] = useState(false);
103	  const persistTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
104	  // Mirror the latest draft so the unmount cleanup can flush whatever is
105	  // pending without closure-capture of stale state.
106	  const draftRef = useRef<WizardDraft>(draft);
107	
108	  useEffect(() => {
109	    draftRef.current = draft;
110	  }, [draft]);
111	
112	  useEffect(() => {
113	    let cancelled = false;
114	    void (async () => {
115	      try {
116	        const raw = await AsyncStorage.getItem(STORAGE_KEY);
117	        if (cancelled) return;
118	        if (raw) {
119	          const parsed: unknown = JSON.parse(raw);
120	          if (isWizardDraftShape(parsed)) {
121	            setDraft(parsed);
122	          }
123	        }
124	      } catch {
125	        // Corrupted / missing draft — start clean. No user-visible error:
126	        // the wizard is a local-first flow and an empty draft is the right
127	        // fallback.
128	      } finally {
129	        if (!cancelled) setHydrated(true);
130	      }
131	    })();
132	    return () => {
133	      cancelled = true;
134	    };
135	  }, []);
136	
137	  const schedulePersist = useCallback((next: WizardDraft) => {
138	    if (persistTimer.current) clearTimeout(persistTimer.current);
139	    persistTimer.current = setTimeout(() => {
140	      void AsyncStorage.setItem(STORAGE_KEY, JSON.stringify(next));
141	    }, PERSIST_DEBOUNCE_MS);
142	  }, []);
143	
144	  useEffect(() => {
145	    return () => {
146	      if (persistTimer.current) {
147	        // Flush pending edit before cancelling. AsyncStorage.setItem is
148	        // async and fire-and-forget here — React unmount paths don't await
149	        // promises, but kicking the write off before clearing the timer is
150	        // what prevents the last keystroke from being dropped if the
151	        // provider unmounts inside the 250 ms debounce window.
152	        clearTimeout(persistTimer.current);
153	        persistTimer.current = null;
154	        void AsyncStorage.setItem(STORAGE_KEY, JSON.stringify(draftRef.current));
155	      }
156	    };
157	  }, []);
158	
159	  const setField = useCallback(
160	    <K extends keyof WizardDraft>(key: K, value: WizardDraft[K]) => {
161	      setDraft((prev) => {
162	        const next = { ...prev, [key]: value };
163	        schedulePersist(next);
164	        return next;
165	      });
166	    },
167	    [schedulePersist],
168	  );
169	
170	  const updateField = useCallback(
171	    <K extends keyof WizardDraft>(
172	      key: K,
173	      updater: (prev: WizardDraft[K]) => WizardDraft[K],
174	    ) => {
175	      setDraft((prev) => {
176	        const next = { ...prev, [key]: updater(prev[key]) };
177	        schedulePersist(next);
178	        return next;
179	      });
180	    },
181	    [schedulePersist],
182	  );
183	
184	  const setPartial = useCallback(
185	    (patch: Partial<WizardDraft>) => {
186	      setDraft((prev) => {
187	        const next = { ...prev, ...patch };
188	        schedulePersist(next);
189	        return next;
190	      });
191	    },
192	    [schedulePersist],
193	  );
194	
195	  const resetDraft = useCallback(async () => {
196	    if (persistTimer.current) {
197	      clearTimeout(persistTimer.current);
198	      persistTimer.current = null;
199	    }
200	    setDraft(EMPTY_DRAFT);
201	    await AsyncStorage.removeItem(STORAGE_KEY);
202	  }, []);
203	
204	  const value = useMemo<WizardContextValue>(
205	    () => ({ draft, hydrated, setField, updateField, setPartial, resetDraft }),
206	    [draft, hydrated, setField, updateField, setPartial, resetDraft],
